import{_ as t,o as e,c as i,a as s}from"./app-2a089349.js";const o={},r=s('<h1 id="import-existing-subscription-prices-from-your-stripe-account" tabindex="-1"><a class="header-anchor" href="#import-existing-subscription-prices-from-your-stripe-account" aria-hidden="true">#</a> Import Existing Subscription Prices from your Stripe Account</h1><p>To save you time, Ultimate Member added a feature where you can simply import the created or existing subscription prices from your Stripe account. When you import the prices, it adds a role to each status automatically. The default role in each subscription status is the role that is set in <strong>WP Admin &gt; Settings &gt; General &gt; New User Default Role</strong>. Ensure that you have read the <a href="/docs-v3/um-stripe/article/1607-stripe-setting-up-webhook-and-test-public-keys">Stripe - Setting up Webhook and Test/Public Keys article</a> before you proceed with the steps below.</p><p>The following steps will guide you on how to import your existing subscription prices from your Stripe account:</p><ul><li>Go to <strong>wp-admin&gt;Ultimate Member&gt; Settings&gt; Extensions&gt;Stripe.</strong></li><li>Click the <strong>&quot;Import Prices from your Stripe Account&quot;</strong> button. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65e4d60be1b845099279232d/file-il6PqdmP6x.png" alt=""></li><li>Once the import is done, It will display all the existing subscription prices you have created in Stripe. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6ea1620e3b82eb738e108/file-AsoMN245C0.png" alt=""></li><li>When you import prices from the Stripe.com account, it should create Stripe Plans automatically and be ready to use. Go to <strong>wp-admin&gt; Ultimate Member&gt; Stripe Plans</strong>. You can see here the following: <ul><li><strong>Plan ID</strong> - You can use this to set the Stripe field&#39;s default selected plan in the Register form via the Form Builder</li><li><strong>Type</strong> - This column displays whether the plan is a one-time or recurring subscription.</li><li><strong>Price</strong> - This column displays the price of the subscription plan.</li><li><strong>Mode</strong> - This column displays the mode in which your prices were imported. The Sandbox displays orange icons indicating that prices were created or imported in Test Mode. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6ef0e270765339befc79f/file-BXP6icxS50.png" alt=""></li></ul></li><li>When you try to edit the Stripe Plan, you will also notice that the <strong>Stripe Type/Mode</strong> and <strong>Stripe Price</strong> are <strong>locked</strong>. This is done to avoid interfering with the Site&#39;s and Stripe.com&#39;s subscriptions. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6f307270765339befc7a1/file-AUUY1YkK9L.png" alt=""></li><li>You can still create your Stripe Plans manually in <strong>UM &gt; Stripe Plans &gt; Add New.</strong> For more info, read this <a href="/docs-v3/um-stripe/article/1617-create-subscription-prices">article.</a></li></ul>',4),n=[r];function a(c,l){return e(),i("div",null,n)}const u=t(o,[["render",a],["__file","1846-import-existing-subscription-prices-from-your-stripe-account.html.vue"]]);export{u as default};
